use std::collections::HashMap;
use std::sync::{Arc, Mutex};

struct MockPeripheral {
    registers: Arc<Mutex<HashMap<u32, u32>>>, 
}

impl MockPeripheral {
    fn new() -> Self {
        MockPeripheral {
            registers: Arc::new(Mutex::new(HashMap::new()))
        }
    }

    fn write_register(&self, address: u32, value: u32) {
        let mut registers = self.registers.lock().unwrap();
        registers.insert(address, value);
    }

    fn read_register(&self, address: u32) -> Option<u32> {
        let registers = self.registers.lock().unwrap();
        registers.get(&address).cloned()
    }
}

struct DataProcessor {
    peripheral: Arc<MockPeripheral>
}

impl DataProcessor {
    fn new(peripheral: Arc<MockPeripheral>) -> Self {
        DataProcessor { peripheral }
    }

    fn process_cycle(&self, control_address: u32) -> Result<u32, &'static str> {
        let read_result = self.peripheral.read_register(control_address);
        match read_result {
            Some(data) => Ok(data + 10), 
            None => Err("Peripheral register not initialized or inaccessible"),
        }
    }
}

fn main() {
    let mock_hw = MockPeripheral::new();
    let control_reg_addr: u32 = 0x4000;
    let initial_data: u32 = 0xFF;

    mock_hw.write_register(control_reg_addr, initial_data);

    let processor = DataProcessor::new(Arc::new(mock_hw));

    match processor.process_cycle(control_reg_addr) {
        Ok(final_value) => println!("Processing cycle completed successfully. Output value: {}", final_value),
        Err(e) => println!("Error during processing: {}", e),
    }
}
